```class Solution {
    public int subtractProductAndSum(int n) {
        int result = 0;
        int product = n;
        int sum = 0;
        while (product != 0) {
            sum += product % 10;
            product /= 10;
        }
        result = sum * (sum + 1) / 2;
        return result;
    }
}
```

